+    assertTypeOf(transform._transform, 'function', 'Transform has _transform method');
+
+    // Custom transform
+    class UpperCaseTransform extends Transform {
+        _transform(chunk, encoding, callback) {
+            const upper = String(chunk).toUpperCase();
+            this.push(upper);
+            callback();
+        }
